// ─── Helper functions ────────────────────────────────────────────────────────

/** Wipe all documents in a Firestore collection */
async function wipeCollection(name: string): Promise<number> {
  const snapshot = await getDocs(collection(db, name));
  let count = 0;
  for (const d of snapshot.docs) {
    await deleteDoc(doc(db, name, d.id));
    count++;
  }
  return count;
}

/** Small delay to avoid Firebase Auth rate limiting */
const delay = (ms: number) => new Promise((r) => setTimeout(r, ms));

/** Generate a random 8-character alphanumeric mixed-case friend code (same as src/lib/utils.ts) */
function generateFriendCode(): string {
  const chars =
    "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";
  let code = "";
  for (let i = 0; i < 8; i++) {
    code += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return code;
}

