// ─── Main seed function ──────────────────────────────────────────────────────

async function seed() {
  console.log("╔══════════════════════════════════════╗");
  console.log("║       SEEDING FIREBASE DATABASE      ║");
  console.log("╚══════════════════════════════════════╝\n");

  // ── Step 1: Wipe all existing data ──────────────────────────────────────
  console.log("① Wiping existing Firestore data...");
  const prodCount = await wipeCollection("products");
  const orderCount = await wipeCollection("orders");
  const userCount = await wipeCollection("users");
  console.log(
    `   Deleted: ${prodCount} products, ${orderCount} orders, ${userCount} users\n`,
  );

  // ── Step 2: Compute salesCount per product from order plans ─────────────
  const salesCounts = new Array(products.length).fill(0);
  for (const plan of ORDER_PLANS) {
    for (const item of plan.items) {
      salesCounts[item.productIdx] += item.qty;
    }
  }

  // ── Step 3: Seed products ───────────────────────────────────────────────
  console.log("② Seeding 25 products...");
  const productIds: string[] = [];

  for (let i = 0; i < products.length; i++) {
    const p = products[i];
    const onSale = p.discount.amount > 0 || p.discount.percentage > 0;
    const featured = p.featured ?? false;

    const docRef = await addDoc(collection(db, "products"), {
      ...p,
      featured,
      onSale,
      viewCount: VIEW_COUNTS[i],
      salesCount: salesCounts[i],
      createdAt: Timestamp.now(),
      updatedAt: Timestamp.now(),
    });
    productIds.push(docRef.id);
    console.log(
      `   ✓ ${p.name} → ${salesCounts[i]} sold, ${VIEW_COUNTS[i]} views` +
        (featured ? " [FEATURED]" : "") +
        (onSale ? " [ON SALE]" : ""),
    );
  }
  console.log();

  // ── Step 4: Seed users (Firebase Auth + Firestore) ──────────────────────
  console.log("③ Seeding 11 users (10 customers + 1 admin)...");
  console.log("   (If user exists in Auth, will sign in to reuse UID)\n");
  const userUids: string[] = [];

  for (let i = 0; i < DEMO_USERS.length; i++) {
    const user = DEMO_USERS[i];
    let uid: string;
    let existed = false;

    try {
      const cred = await createUserWithEmailAndPassword(
        auth,
        user.email,
        DEMO_PASSWORD,
      );
      uid = cred.user.uid;
    } catch (err: any) {
      if (err.code === "auth/email-already-in-use") {
        const cred = await signInWithEmailAndPassword(
          auth,
          user.email,
          DEMO_PASSWORD,
        );
        uid = cred.user.uid;
        existed = true;
      } else {
        console.error(`   ✗ Failed: ${user.email}`, err.message);
        throw err;
      }
    }

    // Write user doc to Firestore (overwrites if exists)
    // Give each customer a saved address (admin gets none)
    const userAddress =
      user.role === "customer"
        ? [
            {
              id: `addr-${i + 1}`,
              addressType: "Residential" as const,
              ...ADDRESSES[i % ADDRESSES.length],
            },
          ]
        : [];

    await setDoc(doc(db, "users", uid), {
      email: user.email,
      displayName: user.displayName,
      role: user.role,
      addresses: userAddress,
      wishlist: [],
      priceWatchers: [],
      autoBuyMessages: [],
      friendCode: generateFriendCode(),
      friends: [],
      incomingRequests: [],
      outgoingRequests: [],
      createdAt: Timestamp.fromDate(user.createdAt),
    });

    userUids.push(uid);
    console.log(
      `   ✓ ${user.displayName.padEnd(16)} ${user.email.padEnd(22)} ${user.role.padEnd(10)} uid: ${uid}` +
        (existed ? " (reused)" : " (created)"),
    );

    // Small delay to avoid Auth rate-limiting
    await delay(300);
  }
  console.log();

  // ── Step 5: Seed orders ─────────────────────────────────────────────────
  console.log("④ Seeding 50 orders...");

  for (let i = 0; i < ORDER_PLANS.length; i++) {
    const plan = ORDER_PLANS[i];
    const userId = userUids[plan.userIdx];

    // Build order items from product data
    const items = plan.items.map((item) => ({
      productId: productIds[item.productIdx],
      name: products[item.productIdx].name,
      price: products[item.productIdx].price,
      quantity: item.qty,
      image: products[item.productIdx].images[0],
    }));

    const totalAmount = items.reduce((s, it) => s + it.price * it.quantity, 0);
    const totalCost = plan.items.reduce(
      (s, it) => s + products[it.productIdx].cost * it.qty,
      0,
    );

    const ts = Timestamp.fromDate(plan.date);

    await addDoc(collection(db, "orders"), {
      userId,
      items,
      totalAmount,
      totalCost,
      shippingAddress: ADDRESSES[plan.userIdx % ADDRESSES.length],
      paymentType: plan.paymentType,
      status: "complete" as const,
      isGift: false,
      isAutoBuy: false,
      createdAt: ts,
      updatedAt: ts,
    });

    const dateStr = plan.date.toLocaleDateString("en-ZA", {
      day: "numeric",
      month: "short",
      year: "numeric",
    });
    const itemNames = plan.items
      .map((it) => products[it.productIdx].name)
      .join(", ");
    console.log(
      `   ✓ #${String(i + 1).padStart(2, "0")}  ${DEMO_USERS[plan.userIdx].displayName.padEnd(16)} ${dateStr.padEnd(14)} ${plan.paymentType.padEnd(18)} ${itemNames}`,
    );
  }

  // ── Summary ─────────────────────────────────────────────────────────────
  const totalUnits = salesCounts.reduce((a: number, b: number) => a + b, 0);
  console.log("\n╔══════════════════════════════════════╗");
  console.log("║            SEED COMPLETE!            ║");
  console.log("╚══════════════════════════════════════╝");
  console.log(`   Products:  ${products.length}`);
  console.log(
    `   Users:     ${DEMO_USERS.length} (${DEMO_USERS.filter((u) => u.role === "customer").length} customers + 1 admin)`,
  );
  console.log(
    `   Orders:    ${ORDER_PLANS.length} (${totalUnits} total units sold)`,
  );
  console.log(`   Period:    May 2025 – Feb 2026`);
  console.log(`   Password:  ${DEMO_PASSWORD} (all users)\n`);

  process.exit(0);
}

seed();
